import type { InputStream, Stack } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';
import { filterFieldKeywords } from '../keywords.js';
import { IncompleteString, String as StringToken } from '../parser.terms.js';
import { getTextFromStream } from '../utils/get-text-from-stream.js';
import { matchCharacterSequence } from '../utils/match-character-sequence.js';

const { BACKSLASH, DOUBLEQUOTE, EOF, SPACE } = characterCodes;

const endString = [DOUBLEQUOTE, EOF];
const acceptStringAfterToken = [
  'ComparisonOperator',
  'JsonPathBase',
  'PositionOperator',
  'SearchOperator',
  'InclusionOperator',
  '","',
];

/**
 * Tokenizer for strings.
 * As opposed to other tokenizers, the string tokenizer is called by the text tokenizer and
 * may either
 * - accept one of the following tokens:
 *    - String
 *    - IncompleteString
 *    - FreeText
 * or
 * - hand back over to the text tokenizer in an indeterminate state.
 * @internal
 */
export function tokenizeString(
  inputStream: InputStream,
  stack: Stack,
  lastTokenizationEndIndexCache: WeakMap<Stack, number>,
  startOffset: number = 0,
): { token?: 'string' | 'indeterminate' | 'json'; offset: number } {
  // Current character is a doublequote.
  // Start checking subsequent characters at offset 1 to see how many we need to include in the token.
  let offset = 1 + startOffset;

  // As long as we don't hit doublequotes again (or the end of the input),
  // keep going to include all the characters in the string token.
  while (!endString.includes(inputStream.peek(offset))) {
    // If the current character is a backslash (escape character), advance once
    // more to skip the escaped character.
    if (
      inputStream.peek(offset) === BACKSLASH &&
      inputStream.peek(offset + 1) !== EOF
    ) {
      offset += 1;
    }

    // Move on to the next character.
    offset += 1;
  }

  const isClosedString = inputStream.peek(offset) === DOUBLEQUOTE;
  const { lastToken, validExpression } = stack.context;

  // We only want to accept a string token if we have matching doublequotes and the token
  // is either preceded by or followed by a valid comparison operator.
  if (isClosedString) {
    let keywordOffset = 1;
    // Skip all spaces that may be present between the closing doublequote and the next character.
    while (inputStream.peek(offset + keywordOffset) === SPACE) {
      keywordOffset += 1;
    }
    const nextChar = inputStream.peek(offset + keywordOffset);

    const { keyword } =
      filterFieldKeywords[String.fromCharCode(nextChar).toLowerCase()] ?? {};

    const hasValidOperator = matchCharacterSequence({
      inputStream,
      offset: offset + keywordOffset,
      characterSequence: keyword ?? [],
    });
    const textBeforeString = getTextFromStream(inputStream, startOffset);

    // Ignore preceding spaces to avoid splitting up a filter starting with a space
    // into multiple statements.
    // E.g. › "foo" = bar‹ the leading space should be ignored.
    if (textBeforeString.length > 0 && textBeforeString.trim() === '') {
      return { token: 'string', offset };
    }

    lastTokenizationEndIndexCache.set(stack, inputStream.pos + offset + 1);

    if (
      hasValidOperator ||
      (acceptStringAfterToken.includes(lastToken) && !validExpression)
    ) {
      inputStream.acceptToken(StringToken, offset + 1);
      return { token: 'string', offset };
    } else {
      offset += 1;
      // Accept FreeText, but may include additional characters.
      return { token: 'indeterminate', offset };
    }
    // If there are no matching doublequotes, the accepted token depends on the
    // last accepted token from the context.
    // E.g.:
    // a = "b
    // --> »›a‹ ›=‹ ›"b‹« statement with incomplete string
    // "b
    // --> ›"b‹ free text
    // foo = \\"*
    // --> »›foo‹ ›=‹ ›\\‹«›"*‹ statement followed by free text
  } else if (
    lastToken === 'expression' ||
    validExpression === true ||
    (lastToken === null && inputStream.peek(offset) === -1)
  ) {
    lastTokenizationEndIndexCache.set(stack, inputStream.pos + offset);
    // Hand back over to the text tokenizer for accepting the actual token.
    return { token: 'indeterminate', offset };
  } else if (lastToken !== null) {
    lastTokenizationEndIndexCache.set(stack, inputStream.pos + offset);
    inputStream.acceptToken(IncompleteString, offset);
    return { token: 'string', offset };
  }

  return { offset: 0 };
}
